var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"......니! 리타 언니! 일어나세요! 어서요!","JPN":"……ね……ちゃん！　リタお姉ちゃん！　目を覚ましてください！　はやく！","ENG":"—ta! Rita! Wake up! Come on!","TWN":"……姐！麗塔姐姐！快醒醒！快！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"죽으면 안 돼요! 제발요!","JPN":"死なないでください！　お願い！","ENG":"Don't die on me! Please!","TWN":"不能死！求你了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hngh...","TWN":"唔……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너는...... 꼬맹이?","JPN":"お前は……ガキ？","ENG":"You... Kid?","TWN":"你是……小鬼？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다행이다......! 언니가 이대로 죽을까 봐 엄청 걱정했어요!","JPN":"よかった……！　このまま死んじゃうんじゃないかと心配したんです！","ENG":"Thank goodness! I was worried sick you might die on me!","TWN":"真是太好了……！我還擔心姐姐就這麼死了呢！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"악몽이었나......? 그렇게 생생했는데?","JPN":"悪夢だったのか……？　結構リアルだったが。","ENG":"Was that a nightmare? But it was so vivid!","TWN":"難道是個噩夢……？太真實了？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 아픈 데는 없어요? 오메르타는 단단하니까 어디 부딪쳐서 다쳤을지도 몰라요.","JPN":"リタお姉ちゃん、具合はどうですか？　オメルタは硬いから打ちどころが悪くて怪我をしているかもしれません。","ENG":"Are you hurt anywhere, Rita? Given how hard Omerta is, you might have hurt yourself bumping into the ground.","TWN":"姐姐，有沒有受傷？奧梅爾塔太堅硬，說不定撞到哪裡受傷了呢。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"몸에 힘이 잘 안 들어가긴 하지만...... 다친 곳은 없어.","JPN":"体に力は入らないけど……怪我はない。","ENG":"I'm feeling a bit lethargic... but otherwise I'm fine.","TWN":"身體有點使不上力氣……但沒受傷。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그보다, 유적에서 찾았던 수정은?","JPN":"それより、遺跡で見つけた水晶は？","ENG":"More importantly, what did you do with the crystal from the ruins?","TWN":"話說回來，在遺跡中拿的水晶呢？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 네! 가방에 잘 넣어 뒀어요!","JPN":"あ、はい！　カバンの中にあります！","ENG":"Oh! I kept it safe in a bag!","TWN":"啊，是！我把它放進背包裡了！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이리 줘 봐.","JPN":"こっちによこせ。","ENG":"Bring it to me.","TWN":"給我。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"수정을 손에 넣은 자에게 <color=#ffd34c>완전한 존재</color>로 거듭날 기회를 주고자 했건만......","JPN":"水晶を手に入れた者に<color=#ffd34c>完全なる存在</color>へと生まれ変わる機会を与えようとしたが……","ENG":"I sought to grant the chance to be reborn as <color=#ffd34c>a perfect being</color> to the one who found the crystal...","TWN":"本想給拿到水晶的人一個成為<color=#ffd34c>完整存在</color>的機會。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 아이는 내 목소리에 귀를 기울이지 않더구나.","JPN":"あの小娘は私の声に耳を貸さなかった。","ENG":"But the child did not heed my voice.","TWN":"但那個孩子聽不到我的聲音。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리, 리타 언니! 수정이 깨졌어요! 어떡해요?!","JPN":"リ、リタお姉ちゃん！　水晶が割れちゃいました！　どうしましょう！？","ENG":"R-Rita! The crystal broke! What are we going to do?!","TWN":"麗、麗塔姐姐！你把水晶打碎了！怎麼辦？！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저런 뭔지도 모를 기분 나쁜 물건은 없애 버리는 편이 더 나아.","JPN":"あんな得体の知れない気味が悪い物は無い方がいい。","ENG":"We're better off without that creepy thing. Who knows what it really is.","TWN":"那種莫名讓人心情很差的東西丟掉反而更好。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만...... 저희한테는 저 수정이 마지막으로 남은 건데......","JPN":"でも……私たちにはあの水晶しか残ってないのに……","ENG":"But... That's all we've got now...","TWN":"但是……對我們來說剩下來的就只有那個水晶……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};